  1→import React from 'react';
  2→import { StyleSheet, Text, View } from 'react-native';
  3→import { Gesture, GestureDetector } from 'react-native-gesture-handler';
  4→import Animated, {
  5→  runOnJS,
  6→  useAnimatedStyle,
  7→  useSharedValue,
  8→  withSpring,
  9→} from 'react-native-reanimated';
