 20→interface VaultItemCardProps {
 21→  item: Item;
 22→  quantity: number;
 23→  onToggle: () => void;
 24→  onIncrement: () => void;
 25→  onDecrement: () => void;
 26→  onDelete: () => void;
 27→}
 28→
 29→const SWIPE_THRESHOLD = 120;
 30→
 31→export const VaultItemCard = React.memo(function VaultItemCard({
 32→  item,
 33→  quantity,
 34→  onToggle,
 35→  onIncrement,
 36→  onDecrement,
 37→  onDelete,
 38→}: VaultItemCardProps) {
 39→  const translateX = useSharedValue(0);
 40→  const bestOption = item.priceOptions[0];
 41→  const priceLabel = bestOption
 42→    ? `${bestOption.store} - ${formatCurrency(bestOption.pricePerUnit.priceValue)}/${bestOption.pricePerUnit.unit}`
 43→    : 'No price set';
 44→
 45→  const panGesture = Gesture.Pan()
 46→    .onUpdate(e => {
 47→      translateX.value = Math.min(0, e.translationX);
 48→    })
 49→    .onEnd(e => {
 50→      if (e.translationX < -SWIPE_THRESHOLD) {
 51→        translateX.value = withSpring(0, motion.snappy);
 52→        runOnJS(onDelete)();
 53→      } else {
 54→        translateX.value = withSpring(0, motion.snappy);
 55→      }
 56→    });
 57→
 58→  const rowStyle = useAnimatedStyle(() => ({
 59→    transform: [{ translateX: translateX.value }],
 60→  }));
 61→
 62→  const revealStyle = useAnimatedStyle(() => ({
 63→    opacity: translateX.value < -20 ? 1 : 0,
 64→  }));
 65→
 66→  return (
 67→    <View
 68→      style={styles.container}
 69→      accessibilityLabel={`${item.name}, ${priceLabel}`}
 70→    >
 71→      <Animated.View style={[styles.revealBg, revealStyle]}>
 72→        <MaterialCommunityIcons name="trash-can-outline" size={28} color={colors.canvas} />
 73→      </Animated.View>
 74→
 75→      <GestureDetector gesture={panGesture}>
 76→        <Animated.View
 77→          style={[styles.row, rowStyle]}
 78→          accessible
 79→          accessibilityActions={[{ name: 'delete', label: 'Delete item' }]}
 80→          onAccessibilityAction={event => {
 81→            if (event.nativeEvent.actionName === 'delete') {
 82→              onDelete();
 83→            }
 84→          }}
 85→        >
 86→          <View style={styles.info} onStartShouldSetResponder={() => false}>
 87→            <Text style={styles.name}>{item.name}</Text>
 88→            {item.notes ? <Text style={styles.description} numberOfLines={2}>{item.notes}</Text> : null}
 89→            <Text style={styles.price}>{priceLabel}</Text>
 90→          </View>
 91→          <AnimatedPressable
 92→            onPress={onDelete}
 93→            accessibilityRole="button"
 94→            accessibilityLabel={`Delete ${item.name}`}
 95→            hitSlop={8}
 96→          >
 97→            <View style={styles.deleteButton}>
 98→              <MaterialCommunityIcons name="trash-can-outline" size={20} color={colors.danger} />
 99→            </View>
100→          </AnimatedPressable>
101→          <SelectionBadge
102→            selected={quantity > 0}
103→            quantity={quantity}
104→            onToggle={onToggle}
105→            onIncrement={onIncrement}
106→            onDecrement={onDecrement}
107→          />
108→        </Animated.View>
109→      </GestureDetector>
110→    </View>
111→  );
112→});
113→
